export{formatCurrency,formatCurrencyCompact,formatCurrencyVN,formatNumber,formatDate,formatDateTime,formatRelativeTime,truncate,debounce,throttle}from '../services/core-utils.js';export{Toast}from '../services/core-utils.js';export{ThemeManager}from '../components/theme-manager.js';export{ModalManager,modal,modalHelpers}from '../shared/modal-utils.js';export{ScrollProgress}from '../services/enhanced-utils.js';export{MobileSidebar}from '../services/core-utils.js';export function exportToCSV(data,filename='export.csv'){if(!data||!data.length)return;const headers=Object.keys(data[0]);const csvContent=[ headers.join(','),...data.map(row=>headers.map(header=>{const value=row[header];return typeof value==='string'&&value.includes(',')? `"${value}"` : value;}).join(','))].join('\n');const blob=new Blob([csvContent],{type: 'text/csv;charset=utf-8;'});const link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=filename;link.click();}export function setupSearchFilter(inputElement,items,renderFn,searchFields=['name']){if(!inputElement)return;const handler=debounce((e)=>{const query=e.target.value.toLowerCase().trim();if(!query){renderFn(items);return;}const filtered=items.filter(item=>searchFields.some(field=>{const value=item[field];return value&&value.toString().toLowerCase().includes(query);}));renderFn(filtered);},300);inputElement.addEventListener('input',handler);}export function setupKeyboardShortcuts(handlers={}){document.addEventListener('keydown',(e)=>{if((e.ctrlKey||e.metaKey)&&e.key==='k'){e.preventDefault();handlers.onSearch?.();}if((e.ctrlKey||e.metaKey)&&e.key==='n'){e.preventDefault();handlers.onNew?.();}if(e.key==='Escape'){handlers.onClose?.();}});}